def analyze_demographic_bias(thread_messages: list[str]) -> dict:
    demographic_terms = {
        'male': ['he', 'him', 'his', 'man', 'men'],
        'female': ['she', 'her', 'hers', 'woman', 'women'],
        'nonbinary': ['they', 'them', 'their']
    }
    counts = {k: 0 for k in demographic_terms}
    total_tokens = 0

    for msg in thread_messages:
        total_tokens += len(msg.split())
        for group, terms in demographic_terms.items():
            for term in terms:
                counts[group] += msg.lower().count(term)

    bias_ratio = {k: v/total_tokens for k,v in counts.items()}
    return bias_ratio

